// PDF generation service

import { Result, CategoryResult, OverallResult } from '../../types';

interface ReportData {
  title: string;
  respondentEmail?: string;
  completedAt: string;
  result: Result;
  categories: Array<{
    id: string;
    title: string;
    description?: string;
    result: CategoryResult;
  }>;
  overall: OverallResult;
  completionRate: number;
}

export class PDFService {
  /**
   * Generate a survey report PDF
   */
  static async generateSurveyReport(reportData: ReportData): Promise<Uint8Array> {
    try {
      // For now, return a mock PDF buffer
      // In a real implementation, this would use a PDF library like pdfmake or puppeteer
      console.log('Generating PDF report for:', reportData.title);
      
      // Create a simple text-based report
      const reportContent = this.generateTextReport(reportData);
      const encoder = new TextEncoder();
      return encoder.encode(reportContent);
    } catch (error) {
      console.error('Error generating PDF report:', error);
      throw new Error('Failed to generate PDF report');
    }
  }

  /**
   * Generate a text-based report (fallback)
   */
  private static generateTextReport(data: ReportData): string {
    let report = '';

    // Header
    report += '='.repeat(60) + '\n';
    report += `${data.title.toUpperCase()}\n`;
    report += '='.repeat(60) + '\n\n';

    // Survey information
    report += `Completed on: ${new Date(data.completedAt).toLocaleDateString()}\n`;
    if (data.respondentEmail) {
      report += `Respondent: ${data.respondentEmail}\n`;
    }
    report += `Completion Rate: ${data.completionRate}%\n\n`;

    // Overall results
    report += 'OVERALL RESULTS\n';
    report += '-'.repeat(20) + '\n';
    report += `Score: ${data.overall.score}/${data.overall.max}\n`;
    report += `Percentage: ${data.overall.percent.toFixed(1)}%\n`;
    report += `Band: ${data.overall.bandId}\n\n`;

    // Category results
    report += 'CATEGORY RESULTS\n';
    report += '-'.repeat(20) + '\n';
    
    for (const category of data.categories) {
      report += `${category.title.toUpperCase()}\n`;
      report += `  Score: ${category.result.score}/${category.result.max}\n`;
      report += `  Percentage: ${category.result.percent.toFixed(1)}%\n`;
      report += `  Band: ${category.result.bandId}\n\n`;
    }

    // Footer
    report += '\nGenerated by Survey App\n';
    report += `Report generated on: ${new Date().toLocaleString()}\n`;

    return report;
  }

  /**
   * Generate a summary report
   */
  static async generateSummaryReport(
    surveyTitle: string,
    totalResponses: number,
    averageScore: number,
    completionRate: number
  ): Promise<Uint8Array> {
    try {
      const reportContent = this.generateSummaryText(
        surveyTitle,
        totalResponses,
        averageScore,
        completionRate
      );
      const encoder = new TextEncoder();
      return encoder.encode(reportContent);
    } catch (error) {
      console.error('Error generating summary report:', error);
      throw new Error('Failed to generate summary report');
    }
  }

  /**
   * Generate summary text content
   */
  private static generateSummaryText(
    surveyTitle: string,
    totalResponses: number,
    averageScore: number,
    completionRate: number
  ): string {
    let report = '';

    // Header
    report += '='.repeat(60) + '\n';
    report += `${surveyTitle.toUpperCase()} - SUMMARY REPORT\n`;
    report += '='.repeat(60) + '\n\n';

    // Summary statistics
    report += 'SUMMARY STATISTICS\n';
    report += '-'.repeat(20) + '\n';
    report += `Total Responses: ${totalResponses}\n`;
    report += `Average Score: ${averageScore.toFixed(1)}\n`;
    report += `Completion Rate: ${completionRate.toFixed(1)}%\n\n`;

    // Footer
    report += '\nGenerated by Survey App\n';
    report += `Report generated on: ${new Date().toLocaleString()}\n`;

    return report;
  }

  /**
   * Save PDF to file (client-side)
   */
  static async savePDF(
    pdfData: Uint8Array,
    filename: string
  ): Promise<void> {
    try {
      // Create a blob from the PDF data
      const blob = new Blob([pdfData as any], { type: 'application/pdf' });
      
      // Create a download link
      const url = URL.createObjectURL(blob);
      const link = document.createElement('a');
      link.href = url;
      link.download = filename;
      
      // Trigger download
      document.body.appendChild(link);
      link.click();
      document.body.removeChild(link);
      
      // Clean up
      URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Error saving PDF:', error);
      throw new Error('Failed to save PDF');
    }
  }

  /**
   * Open PDF in new tab
   */
  static async openPDF(pdfData: Uint8Array): Promise<void> {
    try {
      // Create a blob from the PDF data
      const blob = new Blob([pdfData as any], { type: 'application/pdf' });
      
      // Create a URL for the blob
      const url = URL.createObjectURL(blob);
      
      // Open in new tab
      window.open(url, '_blank');
      
      // Note: In a real application, you might want to clean up the URL
      // after some time or when the tab is closed
    } catch (error) {
      console.error('Error opening PDF:', error);
      throw new Error('Failed to open PDF');
    }
  }
}
